fn solve(grid: Vec<Vec<i64>>, x: i64, y: i64, k: i64) -> Vec<Vec<i64>> {
    let mut result: Vec<Vec<i64>> = grid.iter().map(|row| row.clone()).collect();

    let mut submatrix = Vec::new();
    for i in 0..k {
        let mut row = Vec::new();
        for j in 0..k {
            row.push(result[x as usize + i][y as usize + j]);
        }
        submatrix.push(row);
    }

    let reversed_submatrix: Vec<Vec<i64>> = submatrix.into_iter().rev().collect();

    for i in 0..k {
        for j in 0..k {
            result[x as usize + i][y as usize + j] = reversed_submatrix[i][j];
        }
    }

    result
}
